import dataclasses, datetime
from typing import Optional
from enum import Enum

class ActionStatus(Enum):
    OPEN = "open"
    IN_PROGRESS = "in_progress"
    COMPLETE = "complete"
    BLOCKED = "blocked"
    CLOSED_NO_IMPACT = "closed_no_impact"

@dataclasses.dataclass
class CostActionItem:
    id: str
    title: str
    description: str
    owner: str
    due_date: datetime.date
    success_metric: str        # e.g. "Reduce cost/conversation by 15% within 30 days"
    ticket_id: str
    status: ActionStatus = ActionStatus.OPEN
    actual_outcome: Optional[str] = None
    created_date: datetime.date = dataclasses.field(default_factory=datetime.date.today)

    @property
    def is_overdue(self) -> bool:
        return self.status == ActionStatus.OPEN and datetime.date.today() > self.due_date

    @property
    def days_remaining(self) -> int:
        return (self.due_date - datetime.date.today()).days

    def complete(self, outcome: str) -> None:
        self.status = ActionStatus.COMPLETE
        self.actual_outcome = outcome

    def format_summary(self) -> str:
        overdue = " ⚠️ OVERDUE" if self.is_overdue else f" ({self.days_remaining}d remaining)"
        return (
            f"[{self.id}] {self.title}\n"
            f"  Owner: {self.owner}  Due: {self.due_date}{overdue}\n"
            f"  Success: {self.success_metric}\n"
            f"  Ticket: {self.ticket_id}  Status: {self.status.value}"
        )


@dataclasses.dataclass
class MeetingActionLog:
    meeting_date: datetime.date
    team: str
    items: list = dataclasses.field(default_factory=list)

    def add(self, item: CostActionItem) -> None:
        self.items.append(item)

    def open_items(self) -> list:
        return [i for i in self.items if i.status in (ActionStatus.OPEN, ActionStatus.IN_PROGRESS)]

    def overdue_items(self) -> list:
        return [i for i in self.items if i.is_overdue]

    def completion_rate(self) -> float:
        closed = [i for i in self.items if i.status in (ActionStatus.COMPLETE, ActionStatus.CLOSED_NO_IMPACT)]
        return len(closed) / len(self.items) if self.items else 0.0

@dataclasses.dataclass
class ActionImpactMeasurement:
    action_id: str
    metric_name: str
    baseline_value: float
    measured_value: float
    measurement_date: datetime.date
    success_threshold: float   # expected value
    unit: str = "$"

    @property
    def actual_change_pct(self) -> float:
        if self.baseline_value == 0:
            return 0.0
        return (self.measured_value - self.baseline_value) / self.baseline_value

    @property
    def met_target(self) -> bool:
        # Assumes lower is better for cost metrics
        return self.measured_value <= self.success_threshold

    def format(self) -> str:
        status = "✅ MET" if self.met_target else "❌ MISSED"
        return (
            f"Action {self.action_id} — {self.metric_name}: "
            f"{self.baseline_value:.3f} → {self.measured_value:.3f} "
            f"({self.actual_change_pct:+.1%})  Target: ≤{self.success_threshold:.3f}  {status}"
        )

import datetime, json
from dataclasses import dataclass

@dataclass
class WeeklyCheckInData:
    team: str
    week_start: datetime.date
    mtd_spend_usd: float
    mtd_budget_usd: float
    wow_change_pct: float        # week-over-week spend change
    cost_per_conv: float
    prior_cost_per_conv: float
    open_action_count: int
    overdue_action_count: int
    anomaly_flags: list[str]

    @property
    def budget_pct(self) -> float:
        return self.mtd_spend_usd / self.mtd_budget_usd

    @property
    def conv_change_pct(self) -> float:
        if self.prior_cost_per_conv == 0:
            return 0.0
        return (self.cost_per_conv - self.prior_cost_per_conv) / self.prior_cost_per_conv

    def render_slack_message(self) -> str:
        budget_icon = "🔴" if self.budget_pct > 1.0 else ("🟡" if self.budget_pct > 0.90 else "✅")
        conv_arrow = "▲" if self.conv_change_pct > 0 else "▼"
        lines = [
            f"*{self.team} — Weekly AI Cost Check-In ({self.week_start})*",
            f"{budget_icon} MTD Spend: ${self.mtd_spend_usd:,.0f} / ${self.mtd_budget_usd:,.0f} "
            f"({self.budget_pct:.0%})   WoW: {'▲' if self.wow_change_pct>0 else '▼'}{abs(self.wow_change_pct):.1%}",
            f"💬 Cost/conversation: ${self.cost_per_conv:.4f}  "
            f"({conv_arrow}{abs(self.conv_change_pct):.1%} vs last week)",
            f"📋 Open actions: {self.open_action_count}  ⚠️ Overdue: {self.overdue_action_count}",
        ]
        if self.anomaly_flags:
            lines.append("*Flags requiring attention:*")
            for flag in self.anomaly_flags:
                lines.append(f"  • {flag}")
        lines.append("_Reply in thread if you have context on any flag above._")
        return "\n".join(lines)
